  <text x="20" y="48" fill="#71717a" font-size="12" font-family="sans-serif">同じ4つのリターン、順序だけが違う(平均年7.5%)</text>
  <text x="20" y="99" fill="#e4e4e7" font-size="13" font-weight="700">A: 下落先行</text>
  <rect x="150" y="72" width="75" height="44" rx="6" fill="#27272a" stroke="#ef4444" stroke-width="1.5"/>
  <text x="187" y="99" fill="#f4f4f5" font-size="14" text-anchor="middle" font-weight="700">-50%</text>
  <rect x="235" y="72" width="75" height="44" rx="6" fill="#27272a" stroke="#ef4444" stroke-width="1.5"/>
  <text x="272" y="99" fill="#f4f4f5" font-size="14" text-anchor="middle" font-weight="700">-20%</text>
  <rect x="320" y="72" width="75" height="44" rx="6" fill="#27272a" stroke="#22c55e" stroke-width="1.5"/>
  <text x="357" y="99" fill="#f4f4f5" font-size="14" text-anchor="middle" font-weight="700">+20%</text>
